+import type { AnyColumn } from '~/column.ts';
+import { is } from '~/entity.ts';
+import { Column } from '~/column.ts';
+import { sql, type SQL, type SQLWrapper } from '../sql.ts';
+
+export type WindowBoundary =
+	| typeof unboundedPreceding
+	| typeof currentRow
+	| typeof unboundedFollowing
+	| { type: 'preceding' | 'following'; value: number };
+
+export interface WindowFrame {
+	type: 'rows' | 'range';
+	from: WindowBoundary;
+	to?: WindowBoundary;
+}
+
+export interface WindowSpec {
+	partitionBy?: SQLWrapper | SQLWrapper[];
+	orderBy?: SQLWrapper | SQLWrapper[];
+	frame?: WindowFrame;
+}
+
+export const unboundedPreceding = { type: 'unbounded preceding' } as const;
+export const currentRow = { type: 'current row' } as const;
+export const unboundedFollowing = { type: 'unbounded following' } as const;
+
+function offsetBoundary(helper: 'preceding' | 'following', value: number): WindowBoundary {
+	if (!Number.isInteger(value) || value < 0) {
+		throw new Error(`${helper}() requires a non-negative integer, received ${value}`);
+	}
+	return { type: helper, value };
+}
+
+export function preceding(value: number): WindowBoundary {
+	return offsetBoundary('preceding', value);
+}
+
+export function following(value: number): WindowBoundary {
+	return offsetBoundary('following', value);
+}
+
+function boundaryPosition(boundary: WindowBoundary): number {
+	if (boundary === unboundedPreceding) return 0;
+	if (boundary === currentRow) return 2;
+	if (boundary === unboundedFollowing) return 4;
+	return boundary.type === 'preceding' ? 1 : 3;
+}
+
+function frame(type: WindowFrame['type'], spec: { from: WindowBoundary; to?: WindowBoundary }): WindowFrame {
+	if (spec.to && boundaryPosition(spec.from) > boundaryPosition(spec.to)) {
+		throw new Error('Window frame "from" boundary must not be ordered after "to"');
+	}
+	return { type, ...spec };
+}
+
+export function rows(spec: { from: WindowBoundary; to?: WindowBoundary }): WindowFrame {
+	return frame('rows', spec);
+}
+
+export function range(spec: { from: WindowBoundary; to?: WindowBoundary }): WindowFrame {
+	return frame('range', spec);
+}
+
+function boundarySql(boundary: WindowBoundary): SQL {
+	if ('type' in boundary && (boundary.type === 'preceding' || boundary.type === 'following')) {
+		return sql.raw(`${boundary.value} ${boundary.type}`);
+	}
+	return sql.raw(boundary.type);
+}
+
+/** @internal */
+export function buildWindowSpec(spec: WindowSpec): SQL {
+	const parts: SQL[] = [];
+	if (spec.partitionBy) {
+		parts.push(sql`partition by ${sql.join(Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy], sql`, `)}`);
+	}
+	if (spec.orderBy) {
+		parts.push(sql`order by ${sql.join(Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy], sql`, `)}`);
+	}
+	if (spec.frame) {
+		const bounds = spec.frame.to
+			? sql`${boundarySql(spec.frame.from)} and ${boundarySql(spec.frame.to)}`
+			: boundarySql(spec.frame.from);
+		parts.push(sql`${sql.raw(spec.frame.type)} ${spec.frame.to ? sql`between ${bounds}` : bounds}`);
+	}
+	return sql.join(parts, sql` `);
+}
+
+export class WindowFunction<T> implements SQLWrapper {
+	constructor(private readonly expression: SQL<T>) {}
+
+	over(spec: WindowSpec | string = {}): SQL<T> {
+		return typeof spec === 'string'
+			? sql`${this.expression} over ${sql.identifier(spec)}`
+			: sql`${this.expression} over (${buildWindowSpec(spec)})`;
+	}
+
+	getSQL(): SQL<T> {
+		return this.expression;
+	}
+}
+
+type Value<T extends SQLWrapper> = T extends AnyColumn ? T['_']['data'] : T extends SQL<infer TValue> ? TValue : unknown;
+type ValueDecoder<T extends SQLWrapper> = T extends AnyColumn ? T : typeof String;
+
+function valueFunction<T extends SQLWrapper>(name: string, expression: T): WindowFunction<Value<T> | null> {
+	return new WindowFunction(sql`${sql.raw(name)}(${expression})`.mapWith(is(expression, Column) ? expression : String) as SQL<Value<T> | null>);
+}
+
+function noArgFunction(name: string): WindowFunction<number> {
+	return new WindowFunction(sql`${sql.raw(name)}()`.mapWith(Number));
+}
+
+function positiveInteger(name: string, value: number): void {
+	if (!Number.isInteger(value) || value <= 0) throw new Error(`${name}() requires a positive integer, received ${value}`);
+}
+
+export function rowNumber(): WindowFunction<number> { return noArgFunction('row_number'); }
+export function rank(): WindowFunction<number> { return noArgFunction('rank'); }
+export function denseRank(): WindowFunction<number> { return noArgFunction('dense_rank'); }
+export function percentRank(): WindowFunction<number> { return noArgFunction('percent_rank'); }
+export function cumeDist(): WindowFunction<number> { return noArgFunction('cume_dist'); }
+
+export function ntile(buckets: number): WindowFunction<number> {
+	positiveInteger('ntile', buckets);
+	return new WindowFunction(sql.raw(`ntile(${buckets})`).mapWith(Number));
+}
+
+export function lag<T extends SQLWrapper>(expression: T): WindowFunction<Value<T> | null>;
+export function lag<T extends SQLWrapper, TDefault extends SQLWrapper>(expression: T, offset: number | undefined, defaultValue: TDefault): WindowFunction<Value<T> | Value<TDefault>>;
+export function lag<T extends SQLWrapper>(expression: T, offset?: number, defaultValue?: SQLWrapper): WindowFunction<Value<T> | null> {
+	return positionalValueFunction('lag', expression, offset, defaultValue) as WindowFunction<Value<T> | null>;
+}
+
+export function lead<T extends SQLWrapper>(expression: T): WindowFunction<Value<T> | null>;
+export function lead<T extends SQLWrapper, TDefault extends SQLWrapper>(expression: T, offset: number | undefined, defaultValue: TDefault): WindowFunction<Value<T> | Value<TDefault>>;
+export function lead<T extends SQLWrapper>(expression: T, offset?: number, defaultValue?: SQLWrapper): WindowFunction<Value<T> | null> {
+	return positionalValueFunction('lead', expression, offset, defaultValue) as WindowFunction<Value<T> | null>;
+}
+
+function positionalValueFunction<T extends SQLWrapper>(name: string, expression: T, offset?: number, defaultValue?: SQLWrapper): WindowFunction<Value<T> | null> {
+	const arguments_ = [expression.getSQL()];
+	if (offset !== undefined) arguments_.push(sql.raw(String(offset)));
+	if (defaultValue !== undefined) arguments_.push(defaultValue.getSQL());
+	return new WindowFunction(sql`${sql.raw(name)}(${sql.join(arguments_, sql`, `)})`.mapWith(is(expression, Column) ? expression : String) as SQL<Value<T> | null>);
+}
+
+export function firstValue<T extends SQLWrapper>(expression: T): WindowFunction<Value<T> | null> { return valueFunction('first_value', expression); }
+export function lastValue<T extends SQLWrapper>(expression: T): WindowFunction<Value<T> | null> { return valueFunction('last_value', expression); }
+export function nthValue<T extends SQLWrapper>(expression: T, nth: number): WindowFunction<Value<T> | null> {
+	positiveInteger('nthValue', nth);
+	return new WindowFunction(sql`nth_value(${expression}, ${sql.raw(String(nth))})`.mapWith(is(expression, Column) ? expression : String) as SQL<Value<T> | null>);
+}
+
+export function windowSum(expression: SQLWrapper): WindowFunction<string | null> { return new WindowFunction(sql`sum(${expression})`.mapWith(String)); }
+export function windowAvg(expression: SQLWrapper): WindowFunction<string | null> { return new WindowFunction(sql`avg(${expression})`.mapWith(String)); }
+export function windowMin<T extends SQLWrapper>(expression: T): WindowFunction<Value<T> | null> { return valueFunction('min', expression); }
+export function windowMax<T extends SQLWrapper>(expression: T): WindowFunction<Value<T> | null> { return valueFunction('max', expression); }
+export function windowCount(expression?: SQLWrapper): WindowFunction<number> { return new WindowFunction(sql`count(${expression ?? sql.raw('*')})`.mapWith(Number)); }
